'use client';

import { useEffect, useState } from 'react';
import { useParams } from 'next/navigation';
import Link from 'next/link';
import { Card, CardHeader, CardTitle, CardContent, CardDescription } from '@/components/ui/card';
import { Bot, CheckCircle2, Circle, Clock, KanbanSquare, Loader2, Play, LayoutDashboard, Target, Zap, ArrowRightCircle } from 'lucide-react';
import { Project, Phase } from '@shared/types/project';
import { Task } from '@shared/types/task';
import { Badge } from '@/components/ui/badge';
import { BackgroundAnimation } from '@/components/ui/background-animation';
import { recomputeTaskStatuses } from '@shared/lib/workflow-execution';
import { cn } from '@shared/lib/utils';

export default function ProjectDashboardPage() {
    const { id } = useParams();
    const [projectData, setProjectData] = useState<{ project: Project, phases: Phase[], tasks: Task[] } | null>(null);
    const [nextAction, setNextAction] = useState<{ next_task: Task | null, reasoning: string } | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        let active = true;
        async function fetchDashboard() {
            try {
                const [projectRes, actionRes] = await Promise.all([
                    fetch(`/api/projects/${id}`),
                    fetch(`/api/ai/next-action?project_id=${id}`)
                ]);

                if (!active) return;

                if (projectRes.ok) {
                    const pData = await projectRes.json();
                    setProjectData(pData);
                }

                if (actionRes.ok) {
                    const aData = await actionRes.json();
                    setNextAction(aData);
                }
            } catch (error) {
                console.error("Dashboard failed to load", error);
            } finally {
                if (active) setLoading(false);
            }
        }

        fetchDashboard();
        return () => { active = false; };
    }, [id]);

    if (loading) {
        return (
            <div className="flex-1 flex items-center justify-center p-12 text-muted-foreground">
                <Loader2 className="w-8 h-8 animate-spin" />
            </div>
        );
    }

    if (!projectData) return <div>Project not found.</div>;

    const { project, tasks: initialTasks } = projectData;

    // Load and Merge Local Modifications
    const localUser = typeof window !== 'undefined' ? localStorage.getItem(`workflow_user_tasks_${id}`) : null;
    const localRemoved = typeof window !== 'undefined' ? localStorage.getItem(`workflow_removed_tasks_${id}`) : null;
    const userTasks: Task[] = localUser ? JSON.parse(localUser) : [];
    const removedIds = new Set(localRemoved ? JSON.parse(localRemoved) : []);

    const mergedTasks = [
        ...initialTasks.filter(t => !removedIds.has(t.id)),
        ...userTasks
    ];

    // Added Fallback for Demo Project in case Backend is seeded poorly
    let demoFallback: Task[] = [];
    if (project.is_demo_project && mergedTasks.length === 0) {
        const now = new Date().toISOString();
        demoFallback = [
            {
                id: 't1', title: 'Strategy Briefing', description: 'Align product mission with market needs.',
                status: 'DONE', task_type: 'HUMAN', graph_order: 1, level: 0,
                phase_id: 'p1', task_order: 1, created_at: now, meta: { source: 'AI', is_removed: false }
            },
            {
                id: 't2', title: 'Data Architecture AI', description: 'Generate optimal schema based on spec.',
                status: 'READY', task_type: 'AI', graph_order: 2, dependency_task_id: 't1', level: 0,
                phase_id: 'p1', task_order: 2, created_at: now, meta: { source: 'AI', is_removed: false }
            },
            {
                id: 't3', title: 'Frontend Scaffold', description: 'Initialize core UI components.',
                status: 'BLOCKED', task_type: 'HUMAN', graph_order: 3, dependency_task_id: 't2', level: 0,
                phase_id: 'p1', task_order: 3, created_at: now, meta: { source: 'AI', is_removed: false }
            }
        ];
    }

    const finalSet = demoFallback.length > 0 ? demoFallback : mergedTasks;
    const recomputed = recomputeTaskStatuses(finalSet);

    // Calculate Progress Stats
    const totalTasks = recomputed.length;
    const completedTasks = recomputed.filter(t => t.status === 'DONE').length;
    const executingTasks = recomputed.filter(t => t.status === 'RUNNING').length;
    const completionPercentage = totalTasks > 0 ? Math.round((completedTasks / totalTasks) * 100) : 0;

    // 1. Identify "Actionable" tasks from our recomputed set
    const actionable = recomputed.filter(t => t.status === 'READY');

    // Sort actionable tasks by order but prioritize AI
    const sorted = [...actionable].sort((a, b) => {
        if (a.task_type === 'AI' && b.task_type !== 'AI') return -1;
        if (a.task_type !== 'AI' && b.task_type === 'AI') return 1;
        return (a.graph_order || 0) - (b.graph_order || 0);
    });

    const recommended = sorted[0];

    return (
        <div className="max-w-7xl mx-auto space-y-10 relative px-6 py-8">
            <BackgroundAnimation className="z-[-10]" />

            {/* Header row */}
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
                <div>
                    <div className="flex items-center gap-3 mb-3">
                        <div className="px-2 py-0.5 bg-primary/10 text-primary rounded-md text-[10px] font-black uppercase tracking-widest border border-primary/20">
                            Execution Context
                        </div>
                    </div>
                    <h1 className="text-4xl font-black tracking-tight mb-2 flex items-center gap-3">
                        <span className="text-muted-foreground/30 font-light tracking-tighter">PROJECT /</span> {project.title}
                        {project.is_demo_project && (
                            <Badge variant="default" className="text-[9px] tracking-[0.2em] h-5 uppercase bg-primary text-primary-foreground border-none shadow-lg">Demo Mode</Badge>
                        )}
                    </h1>
                    <p className="text-muted-foreground/80 max-w-2xl text-lg font-medium">"{project.goal_description}"</p>
                </div>
                <div className="flex gap-4">
                    <Link
                        href={`/project/${id}/board`}
                        className="group flex items-center gap-3 bg-card border border-border/60 text-foreground px-8 py-4 rounded-2xl font-black uppercase tracking-widest text-xs hover:border-primary/40 transition-all shadow-xl hover:shadow-primary/5 active:scale-95"
                    >
                        <LayoutDashboard className="w-4 h-4 text-primary" />
                        Infrastructure
                    </Link>
                    <Link
                        href={`/project/${id}/board`}
                        className="group flex items-center gap-3 bg-primary text-primary-foreground px-8 py-4 rounded-2xl font-black uppercase tracking-widest text-xs hover:opacity-90 transition-all shadow-2xl shadow-primary/20 border border-primary/20 active:scale-95"
                    >
                        <KanbanSquare className="w-4 h-4" />
                        Management Board
                    </Link>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

                {/* Progress Dashboard Column */}
                <div className="col-span-1 space-y-8">
                    <Card className="border-border/40 shadow-2xl bg-card/80 backdrop-blur-xl rounded-[2.5rem] overflow-hidden">
                        <div className="p-8 border-b border-border/40 bg-muted/30">
                            <h3 className="text-sm font-black uppercase tracking-widest text-muted-foreground/60 flex items-center gap-2">
                                <Target className="w-4 h-4" />
                                Overall Progress
                            </h3>
                        </div>
                        <div className="p-10">
                            <div className="flex items-end justify-between mb-8">
                                <div className="space-y-1">
                                    <span className="text-[10px] font-black uppercase text-muted-foreground tracking-tighter">Current Completion</span>
                                    <h4 className="text-7xl font-black tracking-tighter text-foreground leading-none">{completionPercentage}%</h4>
                                </div>
                                <Badge variant="success" className="h-6 px-3 text-[10px] font-black tracking-[0.1em] uppercase bg-emerald-500 text-white border-none shadow-lg shadow-emerald-500/20">LIVE SYNC</Badge>
                            </div>
                            <div className="w-full h-4 bg-muted/50 rounded-full overflow-hidden mb-12 border border-border/20 p-1">
                                <div
                                    className="h-full bg-gradient-to-r from-primary to-indigo-400 rounded-full shadow-[0_0_20px_rgba(var(--primary),0.6)] transition-all duration-1000 ease-[cubic-bezier(0.85,0,0.15,1)]"
                                    style={{ width: `${completionPercentage}%` }}
                                />
                            </div>

                            <div className="space-y-6">
                                <div className="flex justify-between items-center bg-muted/20 p-5 rounded-2xl border border-border/40 group hover:border-primary/20 transition-colors">
                                    <div className="flex items-center gap-4">
                                        <div className="w-10 h-10 rounded-full bg-blue-500/10 flex items-center justify-center border border-blue-500/20">
                                            <Zap className="w-4 h-4 text-blue-500" />
                                        </div>
                                        <span className="text-[11px] font-black uppercase text-muted-foreground/80 tracking-widest">Total Workload</span>
                                    </div>
                                    <span className="text-xl font-black text-foreground">{totalTasks}</span>
                                </div>
                                <div className="flex justify-between items-center bg-muted/20 p-5 rounded-2xl border border-border/40 group hover:border-emerald-500/20 transition-colors">
                                    <div className="flex items-center gap-4">
                                        <div className="w-10 h-10 rounded-full bg-emerald-500/10 flex items-center justify-center border border-emerald-500/20">
                                            <CheckCircle2 className="w-4 h-4 text-emerald-500" />
                                        </div>
                                        <span className="text-[11px] font-black uppercase text-muted-foreground/80 tracking-widest">Completed</span>
                                    </div>
                                    <span className="text-xl font-black text-emerald-500">{completedTasks}</span>
                                </div>
                                <div className="flex justify-between items-center bg-primary/5 p-5 rounded-2xl border border-primary/10 group">
                                    <div className="flex items-center gap-4">
                                        <div className="w-10 h-10 rounded-full bg-primary/10 flex items-center justify-center border border-primary/20">
                                            <Play className="w-4 h-4 text-primary" />
                                        </div>
                                        <span className="text-[11px] font-black uppercase text-primary/80 tracking-widest">Active Units</span>
                                    </div>
                                    <span className="text-xl font-black text-primary">{executingTasks}</span>
                                </div>
                            </div>
                        </div>
                    </Card>
                </div>

                {/* AI Next Best Action Column */}
                <div className="col-span-1 lg:col-span-2">
                    <Card className="h-full border-primary/20 shadow-2xl rounded-[2.5rem] overflow-hidden bg-card/50 backdrop-blur-sm border-t-4 border-t-primary relative">
                        <div className="absolute top-0 right-0 p-10 opacity-[0.03] pointer-events-none">
                            <Bot className="w-64 h-64" />
                        </div>

                        <div className="p-8 border-b border-border/40 bg-primary/[0.02] flex items-center justify-between">
                            <div className="flex items-center gap-3">
                                <div className="p-2 bg-primary/10 rounded-xl">
                                    <Bot className="w-5 h-5 text-primary" />
                                </div>
                                <div>
                                    <span className="text-[10px] font-black tracking-[0.3em] text-primary uppercase block">Autonomous Decision Engine</span>
                                    <h3 className="text-xl font-black tracking-tight">Active Recommendations</h3>
                                </div>
                            </div>
                            <div className="flex items-center gap-2 px-3 py-1 bg-emerald-500/10 rounded-full border border-emerald-500/20 text-emerald-600 text-[10px] font-bold uppercase tracking-widest">
                                <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
                                Strategist Online
                            </div>
                        </div>

                        <div className="p-10 flex flex-col h-[calc(100%-100px)]">
                            {!recommended ? (
                                <div className="flex-1 flex flex-col items-center justify-center p-12 bg-muted/20 border border-dashed border-border/60 rounded-[2.5rem] text-center gap-6">
                                    <div className="w-20 h-20 rounded-full bg-emerald-500/10 flex items-center justify-center border-2 border-emerald-500/20 relative">
                                        <div className="absolute inset-0 rounded-full bg-emerald-500/20 animate-ping opacity-40" />
                                        <CheckCircle2 className="w-10 h-10 text-emerald-500" />
                                    </div>
                                    <div className="max-w-md space-y-2">
                                        <h4 className="font-black text-3xl tracking-tight">Mission Accomplished</h4>
                                        <p className="text-muted-foreground/70 font-medium">
                                            {completedTasks === totalTasks && totalTasks > 0
                                                ? "Project structure is 100% complete. All modules have been deployed and verified."
                                                : totalTasks === 0 ? "No project structure identified. Inject tasks via the Management Board." : "Awaiting user input or external dependency resolution."}
                                        </p>
                                    </div>
                                    <Link href={`/project/${id}/board`} className="bg-primary text-white px-8 py-3 rounded-xl font-bold text-xs uppercase tracking-widest shadow-xl shadow-primary/20 hover:scale-105 transition-all">
                                        Open Board
                                    </Link>
                                </div>
                            ) : (
                                <div className="flex-1 flex flex-col gap-8">
                                    <div className="p-10 bg-muted/40 rounded-[2.5rem] border border-border/40 relative group transition-all hover:bg-muted/60">
                                        <div className="absolute top-8 right-8">
                                            <Zap className={cn("w-12 h-12 transition-all", recommended.task_type === 'AI' ? "text-primary opacity-20" : "text-amber-500 opacity-20")} />
                                        </div>

                                        <div className="space-y-1 mb-6">
                                            <Badge variant={recommended.task_type === 'AI' ? 'ai' : 'human'} className="text-[10px] font-black tracking-[0.2em] px-3 py-1 uppercase border-none shadow-md">
                                                {recommended.task_type} EXECUTION UNIT
                                            </Badge>
                                            <h3 className="text-5xl font-black text-foreground tracking-tighter leading-none pt-2">{recommended.title}</h3>
                                        </div>

                                        <p className="text-lg text-muted-foreground/80 font-medium leading-relaxed max-w-2xl mb-10">
                                            {recommended.description}
                                        </p>

                                        <div className="bg-card rounded-3xl p-8 border border-border/40 shadow-inner group-hover:bg-card/80 transition-all">
                                            <div className="flex items-center gap-3 mb-4">
                                                <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center border border-primary/20">
                                                    <Target className="w-4 h-4 text-primary" />
                                                </div>
                                                <span className="text-[10px] font-black uppercase text-primary tracking-widest">Strategist Reasoning</span>
                                            </div>
                                            <p className="text-base text-foreground font-bold tracking-tight italic leading-relaxed">
                                                "{recommended.task_type === 'AI'
                                                    ? `Autonomous step identified. This ${recommended.capability || 'technical'} task can be handled instantly by the AI agent to unblock downstream stages.`
                                                    : `Human intelligence required. Prerequisites are cleared, allowing you to focus on this validation step.`}"
                                            </p>
                                        </div>
                                    </div>

                                    <div className="mt-auto">
                                        <Link
                                            href={`/project/${id}/task/${recommended.id}`}
                                            className="group flex items-center justify-between bg-primary text-primary-foreground p-2 rounded-[2rem] shadow-2xl shadow-primary/30 transition-all hover:scale-[1.01] active:scale-[0.99] border-4 border-primary/20"
                                        >
                                            <div className="flex items-center gap-5 ml-8 font-black uppercase tracking-[0.2em] text-[11px]">
                                                <ArrowRightCircle className="w-5 h-5 group-hover:scale-125 transition-transform" />
                                                Start Work Item
                                            </div>
                                            <div className="bg-white/10 backdrop-blur-sm px-10 py-5 rounded-[1.7rem] font-black uppercase text-sm tracking-widest group-hover:bg-white/20 transition-colors">
                                                Engage Agent
                                            </div>
                                        </Link>
                                    </div>
                                </div>
                            )}
                        </div>
                    </Card>
                </div>
            </div>
        </div>
    );
}
