import * as React from "react"
import { cn } from "@shared/lib/utils"

const Card = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
    ({ className, ...props }, ref) => (
        <div
            ref={ref}
            className={cn(
                "rounded-xl border border-border/50 bg-card text-card-foreground shadow-sm transition-all hover:shadow-md",
                className
            )}
            {...props}
        />
    )
)
Card.displayName = "Card"

